**`components/site/VisualDiffViewer.tsx`:**

```tsx
"use client";
import { useState } from "react";

export function VisualDiffViewer({
  baselineSrc, currentSrc, diffSrc,
}: {
  baselineSrc: string;
  currentSrc: string;
  diffSrc: string;
}) {
  const [mode, setMode] = useState<"side" | "diff">("side");
  return (
    <div className="grid gap-2">
      <div className="flex gap-2">
        <button
          className={`text-xs px-2 py-1 rounded ${mode === "side" ? "bg-primary text-primary-foreground" : "bg-secondary"}`}
          onClick={() => setMode("side")}
        >좌우 비교</button>
        <button
          className={`text-xs px-2 py-1 rounded ${mode === "diff" ? "bg-primary text-primary-foreground" : "bg-secondary"}`}
          onClick={() => setMode("diff")}
        >diff 보기</button>
      </div>
      {mode === "side" ? (
        <div className="grid grid-cols-2 gap-2">
          <img src={baselineSrc} className="w-full border" alt="baseline" />
          <img src={currentSrc} className="w-full border" alt="current" />
        </div>
      ) : (
        <img src={diffSrc} className="w-full border" alt="diff" />
      )}
    </div>
  );
}
```

**`components/site/PageDiffCard.tsx`:**

```tsx
import type { PageDiff } from "@/lib/site-types";
import { VisualDiffViewer } from "./VisualDiffViewer";

export function PageDiffCard({
  diff, baselineSrc, currentSrc,
}: {
  diff: PageDiff;
  baselineSrc?: string;
  currentSrc?: string;
}) {
  const color =
    diff.severity === "critical" ? "border-red-500" :
    diff.severity === "warning" ? "border-amber-500" : "border-emerald-500";
  return (
    <article className={`rounded border-l-4 ${color} bg-card p-4`}>
      <header className="flex items-center justify-between mb-2">
        <div>
          <div className="font-mono text-sm">{diff.url}</div>
          <div className="text-xs text-muted-foreground">
            status={diff.status} · severity={diff.severity}
          </div>
        </div>
        {diff.visualDiff && (
          <div className="text-xs">
            diffRatio: {(diff.visualDiff.diffRatio * 100).toFixed(2)}%
          </div>
        )}
      </header>
      {diff.status !== "identical" && diff.status !== "missing" && baselineSrc && currentSrc && diff.visualDiff && (
        <VisualDiffViewer
          baselineSrc={baselineSrc}
          currentSrc={currentSrc}
          diffSrc={`/api/sites/${encodeURIComponent(diff.url)}`}
        />
      )}
    </article>
  );
}
```

**`app/sites/[id]/report/[runId]/page.tsx`** (디렉터리 포함):

```tsx
"use client";
import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { PageDiffCard } from "@/components/site/PageDiffCard";
import type { SiteReport, SiteRunResult } from "@/lib/site-types";

export default function ReportPage() {
  const params = useParams<{ id: string; runId: string }>();
  const [report, setReport] = useState<SiteReport | null>(null);
  const [current, setCurrent] = useState<SiteRunResult | null>(null);

  useEffect(() => {
    void (async () => {
      const [r1, r2] = await Promise.all([
        fetch(`/api/sites/${params.id}/runs/${params.runId}/report`).then((r) => r.json()),
        fetch(`/api/sites/${params.id}/runs/${params.runId}`).then((r) => r.json()),
      ]);
      if (r1.success) setReport(r1.data);
      if (r2.success) setCurrent(r2.data);
    })();
  }, [params.id, params.runId]);

  if (!report) return <main className="px-4 py-8">불러오는 중...</main>;

  const fileByUrl = new Map(
    (current?.pages ?? []).map((p) => [
      p.url,
      p.screenshotPath ? p.screenshotPath.split(/[\\/]/).pop() : undefined,
    ])
  );

  return (
    <main className="px-4 py-8 grid gap-3">
      <header className="mb-4">
        <h1 className="text-2xl font-bold">회귀 리포트</h1>
        <div className="text-sm text-muted-foreground">
          overall: {report.overall} · baseline {report.baselineRunId} → current {report.currentRunId}
        </div>
      </header>
      {report.pageDiffs.map((d) => {
        const file = fileByUrl.get(d.url);
        return (
          <PageDiffCard
            key={d.url}
            diff={d}
            baselineSrc={file ? `/api/sites/${params.id}/baseline/screenshot/${file}` : undefined}
            currentSrc={file ? `/api/sites/${params.id}/runs/${params.runId}/screenshot/${file}` : undefined}
          />
        );
      })}
    </main>
  );
}
```

